DECLARE @Now DATETIME2 = SYSUTCDATETIME();

DECLARE @Preferences TABLE (
    Id UNIQUEIDENTIFIER NOT NULL PRIMARY KEY,
    UserId UNIQUEIDENTIFIER NOT NULL,
    PreferredCategories NVARCHAR(500) NOT NULL,
    BudgetLevel NVARCHAR(20) NOT NULL,
    PacePreference NVARCHAR(20) NOT NULL,
    UpdatedOffsetHours INT NOT NULL
);


MERGE intel.UserPreferences AS target
USING @Preferences AS source
ON target.UserId = source.UserId
WHEN MATCHED THEN UPDATE SET
    PreferredCategories = source.PreferredCategories,
    BudgetLevel = source.BudgetLevel,
    PacePreference = source.PacePreference,
    UpdatedAt = DATEADD(HOUR, -source.UpdatedOffsetHours, @Now)
WHEN NOT MATCHED THEN INSERT (Id, UserId, PreferredCategories, BudgetLevel, PacePreference, UpdatedAt)
VALUES (source.Id, source.UserId, source.PreferredCategories, source.BudgetLevel, source.PacePreference, DATEADD(HOUR, -source.UpdatedOffsetHours, @Now));

DECLARE @SpotFeatures TABLE (
    Id UNIQUEIDENTIFIER NOT NULL PRIMARY KEY,
    SpotId UNIQUEIDENTIFIER NOT NULL,
    FeatureVector NVARCHAR(MAX) NOT NULL,
    PopularityScore FLOAT NOT NULL,
    SentimentScore FLOAT NOT NULL,
    UpdatedOffsetHours INT NOT NULL
);


MERGE intel.SpotFeatures AS target
USING @SpotFeatures AS source
ON target.SpotId = source.SpotId
WHEN MATCHED THEN UPDATE SET
    FeatureVector = source.FeatureVector,
    PopularityScore = source.PopularityScore,
    SentimentScore = source.SentimentScore,
    UpdatedAt = DATEADD(HOUR, -source.UpdatedOffsetHours, @Now)
WHEN NOT MATCHED THEN INSERT (Id, SpotId, FeatureVector, PopularityScore, SentimentScore, UpdatedAt)
VALUES (source.Id, source.SpotId, source.FeatureVector, source.PopularityScore, source.SentimentScore, DATEADD(HOUR, -source.UpdatedOffsetHours, @Now));

MERGE intel.ItineraryCache AS target
USING (
    SELECT CAST('13131313-1313-1313-1313-000000000005' AS UNIQUEIDENTIFIER) AS Id, CAST('eeeeeeee-eeee-eeee-eeee-eeeeeeeeeee9' AS UNIQUEIDENTIFIER) AS UserId, N'demo-trip-5-showcase-route' AS RequestHash, N'{"title":"Desert Lights to Canyon Country","destination":"Las Vegas, Moab, Sedona","stops":["Las Vegas Arts District First Friday","Moab Main Street Canyon Base","Sedona Airport Mesa Sunset"],"estimatedBudget":1620,"grounding":"verified seeded public places"}' AS ResultJson, DATEADD(DAY, 14, @Now) AS ExpiresAt, DATEADD(HOUR, -2, @Now) AS CreatedAt
    UNION ALL
    SELECT CAST('13131313-1313-1313-1313-000000000006' AS UNIQUEIDENTIFIER) AS Id, CAST('ffffffff-ffff-ffff-ffff-fffffffffff9' AS UNIQUEIDENTIFIER) AS UserId, N'demo-trip-6-showcase-route' AS RequestHash, N'{"title":"Southern Music and Coastal Cities","destination":"Nashville, Charleston, Savannah, Biloxi, Birmingham","stops":["Nashville Broadway Live Block","Charleston Battery Morning Walk","Savannah Forsyth Fountain Loop","Biloxi Gulf Islands Ferry Dock","Birmingham Railroad Park Greenway"],"estimatedBudget":1880,"grounding":"verified seeded public places"}' AS ResultJson, DATEADD(DAY, 14, @Now) AS ExpiresAt, DATEADD(HOUR, -3, @Now) AS CreatedAt
    UNION ALL
    SELECT CAST('13131313-1313-1313-1313-000000000007' AS UNIQUEIDENTIFIER) AS Id, CAST('cccccccc-cccc-cccc-cccc-ccccccccccc1' AS UNIQUEIDENTIFIER) AS UserId, N'demo-trip-7-showcase-route' AS RequestHash, N'{"title":"Route 66 Heartland Weekend","destination":"Tulsa, St. Louis, Chicago","stops":["Tulsa Route 66 Neon Gateway","St. Louis Gateway Arch Riverfront","Millennium Park Bean Loop"],"estimatedBudget":980,"grounding":"verified seeded public places"}' AS ResultJson, DATEADD(DAY, 14, @Now) AS ExpiresAt, DATEADD(HOUR, -4, @Now) AS CreatedAt
    UNION ALL
    SELECT CAST('13131313-1313-1313-1313-000000000008' AS UNIQUEIDENTIFIER) AS Id, CAST('cdcdcdcd-cdcd-cdcd-cdcd-cdcdcdcdcd01' AS UNIQUEIDENTIFIER) AS UserId, N'demo-trip-8-showcase-route' AS RequestHash, N'{"title":"Northern Lakes and Market Cities","destination":"Minneapolis, Milwaukee, Detroit, Chicago","stops":["Minneapolis Stone Arch River View","Milwaukee Third Ward Market","Detroit Eastern Market Saturday","Millennium Park Bean Loop"],"estimatedBudget":1320,"grounding":"verified seeded public places"}' AS ResultJson, DATEADD(DAY, 14, @Now) AS ExpiresAt, DATEADD(HOUR, -5, @Now) AS CreatedAt
) AS source
ON target.RequestHash = source.RequestHash
WHEN MATCHED THEN UPDATE SET
    UserId = source.UserId,
    ResultJson = source.ResultJson,
    ExpiresAt = source.ExpiresAt
WHEN NOT MATCHED THEN INSERT (Id, UserId, RequestHash, ResultJson, ExpiresAt, CreatedAt)
VALUES (source.Id, source.UserId, source.RequestHash, source.ResultJson, source.ExpiresAt, source.CreatedAt);
GO
